import{_ as t,c as i,o as s,ag as a}from"./chunks/framework.Dj4VfQLU.js";const u=JSON.parse('{"title":"Passkey Authentication Setup","description":"","frontmatter":{"icon":"key"},"headers":[],"relativePath":"passkey-authentication.md","filePath":"passkey-authentication.md"}'),o={name:"passkey-authentication.md"};function n(r,e,l,p,d,c){return s(),i("div",null,e[0]||(e[0]=[a(`<h1 id="passkey-authentication-setup" tabindex="-1">Passkey Authentication Setup <a class="header-anchor" href="#passkey-authentication-setup" aria-label="Permalink to &quot;Passkey Authentication Setup&quot;">​</a></h1><p>Passkey authentication (WebAuthn) provides a secure, passwordless login experience using biometric authentication like Face ID, Touch ID, or Windows Hello. This guide covers how to enable and configure passkey support for your BetterTaxi deployment.</p><hr><h4 id="🔑-what-is-passkey-authentication" tabindex="-1">🔑 What is Passkey Authentication? <a class="header-anchor" href="#🔑-what-is-passkey-authentication" aria-label="Permalink to &quot;🔑 What is Passkey Authentication?&quot;">​</a></h4><p>Passkeys are a modern authentication method that replaces passwords with cryptographic key pairs stored securely on the user&#39;s device. Benefits include:</p><ul><li><strong>Phishing-resistant</strong> - Credentials are bound to the origin domain</li><li><strong>No password to remember</strong> - Uses biometrics (fingerprint, face) or device PIN</li><li><strong>Cross-device sync</strong> - Apple and Google sync passkeys across devices</li><li><strong>Fast login</strong> - One-tap authentication after initial setup</li></ul><hr><h4 id="⚙️-backend-configuration" tabindex="-1">⚙️ Backend Configuration <a class="header-anchor" href="#⚙️-backend-configuration" aria-label="Permalink to &quot;⚙️ Backend Configuration&quot;">​</a></h4><p>Configure the following environment variables in your backend API servers (rider-api, driver-api):</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Passkey / WebAuthn Configuration</span></span>
<span class="line"><span>PASSKEY_RP_ID=yourdomain.com</span></span>
<span class="line"><span>PASSKEY_RP_NAME=YourAppName</span></span>
<span class="line"><span>PASSKEY_ORIGIN=https://yourdomain.com</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>PASSKEY_RP_ID</code></td><td>The domain identifier (Relying Party ID). Must match the domain users access.</td><td><code>api.bettersuite.io</code> or <code>localhost</code></td></tr><tr><td><code>PASSKEY_RP_NAME</code></td><td>Human-readable app name shown during registration</td><td><code>BetterTaxi</code>, <code>MyRideApp</code></td></tr><tr><td><code>PASSKEY_ORIGIN</code></td><td>Full origin URL including protocol</td><td><code>https://app.bettersuite.io</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The <code>PASSKEY_RP_ID</code> must exactly match the domain where users access your app (without protocol). For development, use <code>localhost</code>.</p></div><p><strong>Default Values</strong> (if not set):</p><ul><li><code>PASSKEY_RP_ID</code>: <code>localhost</code></li><li><code>PASSKEY_RP_NAME</code>: <code>BetterSuite</code></li><li><code>PASSKEY_ORIGIN</code>: <code>https://localhost</code></li></ul><hr><h4 id="🗄️-database-requirements" tabindex="-1">🗄️ Database Requirements <a class="header-anchor" href="#🗄️-database-requirements" aria-label="Permalink to &quot;🗄️ Database Requirements&quot;">​</a></h4><p>The passkey feature requires the <code>auth_method</code> table. Ensure the migration has been applied:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Migration file: 1763232553000-auth-method-module.ts</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># This runs automatically on API startup</span></span></code></pre></div><p>If you&#39;re upgrading from a previous version, restart your API servers to apply pending migrations.</p><hr><h4 id="📱-frontend-configuration" tabindex="-1">📱 Frontend Configuration <a class="header-anchor" href="#📱-frontend-configuration" aria-label="Permalink to &quot;📱 Frontend Configuration&quot;">​</a></h4><p>Enable passkey authentication in your Flutter apps by setting the environment variable in <code>.env.dev</code> and <code>.env.prod</code>:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Enable passkey authentication</span></span>
<span class="line"><span>PASSKEY_ENABLED=true</span></span></code></pre></div><p><strong>Location of .env files:</strong></p><ul><li>Rider App: <code>apps/taxi-rider-frontend/.env.dev</code> / <code>.env.prod</code></li><li>Driver App: <code>apps/taxi-driver-frontend/.env.dev</code> / <code>.env.prod</code></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>After changing environment variables, rebuild the app to apply changes.</p></div><hr><h4 id="🍎-ios-setup-required" tabindex="-1">🍎 iOS Setup (Required) <a class="header-anchor" href="#🍎-ios-setup-required" aria-label="Permalink to &quot;🍎 iOS Setup (Required)&quot;">​</a></h4><p>iOS requires <strong>Associated Domains</strong> to be configured for passkey authentication to work. This links your app with your server domain.</p><p><strong>Step 1: Configure environment variables</strong></p><p>Add these to your root <code>.env</code> file:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Apple App Site Association (for passkey)</span></span>
<span class="line"><span>APPLE_TEAM_ID=YOUR_TEAM_ID</span></span>
<span class="line"><span>RIDER_BUNDLE_ID=com.yourcompany.rider</span></span>
<span class="line"><span>DRIVER_BUNDLE_ID=com.yourcompany.driver</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Find your Team ID in the <a href="https://developer.apple.com" target="_blank" rel="noreferrer">Apple Developer Portal</a> under <strong>Membership Details</strong>.</p></div><p><strong>Step 2: Deploy and verify the association file</strong></p><p>Both rider-api and driver-api automatically serve the <code>apple-app-site-association</code> file at:</p><ul><li><code>https://yourdomain.com/.well-known/apple-app-site-association</code></li></ul><p>After deploying, verify the file is accessible:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://yourdomain.com/.well-known/apple-app-site-association</span></span></code></pre></div><p>Expected response:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;webcredentials&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;apps&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;TEAMID.com.yourcompany.rider&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;TEAMID.com.yourcompany.driver&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Step 3: Update iOS entitlements</strong></p><p>The Flutter apps are pre-configured with Associated Domains. Update the domain in:</p><ul><li><code>apps/taxi-rider-frontend/ios/Runner/Runner.entitlements</code></li><li><code>apps/taxi-driver-frontend/ios/Runner/Runner.entitlements</code></li></ul><p>Replace <code>yourdomain.com</code> with your actual <code>PASSKEY_RP_ID</code> domain:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">key</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;com.apple.developer.associated-domains&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">key</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">array</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;webcredentials:yourdomain.com&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">array</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>For local development, add <code>?mode=developer</code> to bypass server verification:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;webcredentials:yourdomain.com?mode=developer&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>Remove <code>?mode=developer</code> for production builds!</p></div><p><strong>Step 4: Enable Associated Domains in Apple Developer Portal</strong></p><ol><li>Go to <a href="https://developer.apple.com" target="_blank" rel="noreferrer">Apple Developer Portal</a></li><li>Navigate to <strong>Certificates, Identifiers &amp; Profiles</strong></li><li>Select your <strong>App ID</strong> (for both rider and driver apps)</li><li>Enable <strong>Associated Domains</strong> capability</li><li>Rebuild and re-sign your app</li></ol><div class="danger custom-block"><p class="custom-block-title">Important</p><p>The domain in your iOS entitlements must exactly match the <code>PASSKEY_RP_ID</code> configured on your backend. Mismatched domains will cause passkey registration/login to fail.</p></div><hr><h4 id="📋-platform-support" tabindex="-1">📋 Platform Support <a class="header-anchor" href="#📋-platform-support" aria-label="Permalink to &quot;📋 Platform Support&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Platform</th><th>Supported</th><th>Requirements</th></tr></thead><tbody><tr><td><strong>iOS</strong></td><td>✅ Yes</td><td>iOS 16+</td></tr><tr><td><strong>Android</strong></td><td>✅ Yes</td><td>Android 9+ with Google Play Services</td></tr><tr><td><strong>Web</strong></td><td>❌ No</td><td>Not currently supported</td></tr><tr><td><strong>Desktop</strong></td><td>❌ No</td><td>Not currently supported</td></tr></tbody></table><hr><h4 id="🚀-user-flows" tabindex="-1">🚀 User Flows <a class="header-anchor" href="#🚀-user-flows" aria-label="Permalink to &quot;🚀 User Flows&quot;">​</a></h4><p><strong>Registration Flow (Post-Login):</strong></p><ol><li>User logs in with phone/email</li><li>After successful login, app prompts to set up passkey</li><li>User authenticates with biometrics</li><li>Passkey is registered and linked to account</li></ol><p><strong>Login Flow:</strong></p><ol><li>User taps &quot;Login with Passkey&quot; on the login screen</li><li>Device shows biometric prompt</li><li>User authenticates with Face ID/Touch ID/PIN</li><li>App receives JWT token and logs user in</li></ol><hr><h4 id="🔧-troubleshooting" tabindex="-1">🔧 Troubleshooting <a class="header-anchor" href="#🔧-troubleshooting" aria-label="Permalink to &quot;🔧 Troubleshooting&quot;">​</a></h4><p><strong>❌ &quot;Passkey not supported on this device&quot;</strong></p><p><strong>Cause:</strong></p><ul><li>Device doesn&#39;t meet minimum OS requirements</li><li>Google Play Services not available (Android)</li><li>Running on web/desktop platform</li></ul><p><strong>Resolution:</strong></p><ul><li>Ensure iOS 16+ or Android 9+ with Play Services</li><li>Use phone/email login as fallback</li></ul><hr><p><strong>❌ &quot;Failed to begin passkey authentication&quot;</strong></p><p><strong>Cause:</strong></p><ul><li>Backend API not reachable</li><li>Redis not running (challenges stored in Redis)</li><li>Invalid <code>PASSKEY_RP_ID</code> configuration</li></ul><p><strong>Resolution:</strong></p><ul><li>Verify API is running and accessible</li><li>Check Redis connection</li><li>Ensure <code>PASSKEY_RP_ID</code> matches your domain</li></ul><hr><p><strong>❌ Passkey works in dev but not production</strong></p><p><strong>Cause:</strong></p><ul><li><code>PASSKEY_RP_ID</code> or <code>PASSKEY_ORIGIN</code> mismatch with production domain</li></ul><p><strong>Resolution:</strong></p><ul><li>Update environment variables to match production domain exactly</li><li><code>PASSKEY_RP_ID</code> should be the domain without protocol (e.g., <code>app.example.com</code>)</li><li><code>PASSKEY_ORIGIN</code> should include the protocol (e.g., <code>https://app.example.com</code>)</li></ul><hr><h4 id="📝-configuration-checklist" tabindex="-1">📝 Configuration Checklist <a class="header-anchor" href="#📝-configuration-checklist" aria-label="Permalink to &quot;📝 Configuration Checklist&quot;">​</a></h4><p><strong>Backend:</strong></p><ul><li>[ ] Set <code>PASSKEY_RP_ID</code> to your domain</li><li>[ ] Set <code>PASSKEY_RP_NAME</code> to your app name</li><li>[ ] Set <code>PASSKEY_ORIGIN</code> to your full origin URL</li><li>[ ] Set <code>APPLE_TEAM_ID</code> to your Apple Team ID</li><li>[ ] Set <code>RIDER_BUNDLE_ID</code> and <code>DRIVER_BUNDLE_ID</code> to your app bundle IDs</li><li>[ ] Ensure Redis is running</li><li>[ ] Restart API servers to apply migrations</li></ul><p><strong>Frontend:</strong></p><ul><li>[ ] Set <code>PASSKEY_ENABLED=true</code> in <code>.env</code> files</li><li>[ ] Rebuild Flutter apps after config changes</li></ul><p><strong>iOS (Required):</strong></p><ul><li>[ ] Update <code>Runner.entitlements</code> with your domain (rider and driver apps)</li><li>[ ] Enable Associated Domains in Apple Developer Portal</li><li>[ ] Verify apple-app-site-association is accessible at your domain</li><li>[ ] Remove <code>?mode=developer</code> suffix for production builds</li></ul><hr><h4 id="🔐-security-notes" tabindex="-1">🔐 Security Notes <a class="header-anchor" href="#🔐-security-notes" aria-label="Permalink to &quot;🔐 Security Notes&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Aspect</th><th>Details</th></tr></thead><tbody><tr><td><strong>Challenge Expiry</strong></td><td>Challenges expire after 5 minutes</td></tr><tr><td><strong>Replay Protection</strong></td><td>Counter is incremented on each authentication</td></tr><tr><td><strong>User Verification</strong></td><td>Required for both registration and login</td></tr><tr><td><strong>Authenticator Type</strong></td><td>Platform authenticators only (no security keys)</td></tr><tr><td><strong>Credential Discovery</strong></td><td>Discoverable credentials enabled for usernameless login</td></tr></tbody></table><blockquote><p>🚀 Passkey authentication is one of the most secure authentication methods available, as credentials never leave the user&#39;s device and are resistant to phishing attacks.</p></blockquote>`,89)]))}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
